var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"흥. 잡종은 도망쳤나.","JPN":"ふん。雑種は逃げたようじゃのう。","ENG":"Hmpf. So the mongrel ran away.","TWN":"哼，小狐狸跑了嗎。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"어디 자기 앞가림도 못하는 풋내기를 칼받이랍시고 끌고 와선.","JPN":"あんな自分のことで手一杯のひよっこを盾よろしく連れてくるとは。","ENG":"Dragging along a kid as a meat shield, when it can’t even take care of itself.","TWN":"打不過就拉來當墊背。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"자기 마음에 안 들면 직접 처리할 것이지.","JPN":"気に入らなければ自分でやれというのじゃ。","ENG":"Doesn't she know to take care of things herself?","TWN":"看不順眼的話就自己上啊。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"이 빚은 장부에 달아 둬야겠어.","JPN":"この借りは必ず返してもらわねばのう。","ENG":"Add this to the tab.","TWN":"這筆賬給我記到本子上。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"물론입니다, 주인님.","JPN":"もちろんです、ご主人様。","ENG":"Of course, Mistress.","TWN":"那當然，主人。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"하지만 언제 보아도 참으로 경이로운 권능이군요.","JPN":"しかし相変わらず、とてつもなく驚異的な権能ですね。","ENG":"I must say, your powers are truly something divine.","TWN":"請允許我讚美您，不管什麼時候看，都是讓人驚訝的能力呢。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"저들도 이 기회에 주인님께서 격이 다르다는 걸 깨달았겠죠.","JPN":"連中もこれを機に、ご主人様の格の違いを思い知ったでしょう。","ENG":"I assume that they’ve realized that they're far behind your league.","TWN":"那些人也借此機會明白與主人的層次不同這件事了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐야, 마왕이라면서 오래 좀 버틸 것이지. 이번에도 손가락 빨면서 구경만 했네.","JPN":"なーんだ、魔王ならもう少し耐えてくれるかと思ったのに。今回も指くわえて見るだけで終わったな。","ENG":"Ugh, I thought a Demon Lord was supposed to last longer. I didn’t even have a chance to join in.","TWN":"什麼嘛，既然是魔王，就應該撐得久一點啊。光看熱鬧一點意思也沒有。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 그래도 오랜만에 몸을 풀었구나.","JPN":"ふふ、しかし久しぶりに準備運動程度にはなった。","ENG":"Fu fu, still, it was nice to finally get some exercise.","TWN":"呵呵，不過我也久違了地活動了一下身體。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"시종, 내 감자칩을 대령하거라.","JPN":"僕、ポテトチップスを用意するのじゃ。","ENG":"Fetch me my chips, servant.","TWN":"僕人，把我的洋芋片拿過來。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"치즈맛으로 하시겠습니까, 양파맛으로 하시겠습니까?","JPN":"チーズ味と、オニオン味、どちらになさいますか？","ENG":"Which flavor would you prefer, Mistress? Cheese or onion?","TWN":"您是要起司口味的，還是要洋蔥口味的？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"바베큐맛이 좋겠구나. 좋은 구경거리를 보러 나온 나들이니 말이다.","JPN":"バーベキュー味にしよう。せっかく面白いものを見に来たのじゃからのう。","ENG":"Barbeque would suffice. Today's stroll is full of pleasantries, after all.","TWN":"既然是出來看熱鬧，那就BBQ口味的吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"주인님의 의중을 헤아리는 것도 제 본분이죠. 그러실 줄 알고 함께 준비해 두었습니다.","JPN":"ご主人様の意中を察するのも私の仕事です。そうおっしゃると思って合わせて用意しておきました。","ENG":"It is my duty to analyze your needs, which is why I have prepared Barbeque as well.","TWN":"了解主人的心情也是我的工作之一。我就知道您會如此，所以也一起準備了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"하온데 주인님, 탐식자의 분체는 소멸했다지만……","JPN":"しかしご主人様、貪食者の分身は消滅しましたが……","ENG":"If you don't mind me asking, Mistress... While the Devourer's fragment has been annihilated...","TWN":"如果您不介意我多嘴的話，雖然貪食者的分裂體已經徹底湮滅了……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DOMA_NPC_NULL_NULL","text":{"KOREA":"사라진 여우는 어떤 처분을 내리시겠습니까?","JPN":"逃げたキツネはどのように処分いたしますか？","ENG":"What should we do with the fox that fled?","TWN":"但您想要如何處置那隻狐狸呢？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"DOMA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"번거롭게 처분은 무슨.","JPN":"処分など面倒じゃ。","ENG":"Nothing. It's too tedious.","TWN":"太麻煩了。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"어차피 그 세상 물정 모르는 잡종이 나돌아다니면, 대마녀라고 뻐기던 계집애가 알아서 해결할 테지.","JPN":"どうせあの世間知らずの雑種が出てくるようになれば、大魔女だといきがっていた小娘が放っておかぬじゃろう。","ENG":"Should the mongrel keep wandering around, it shall be taken care of by the girl who claims to be the Great Witch or whatever.","TWN":"要是她還不長記性，那個自稱是大魔女的丫頭會看著辦的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};